import { useMemo, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Visualization from './pages/Visualization';
import DashboardPage from './pages/DashboardPage';
import SearchPage from './pages/SearchPage';
import UploadTilePage from './pages/UploadTilePage';
import CataloguePage from './pages/CataloguePage';
import SettingsPage from './pages/SettingsPage';
import EnterpriseLayout from './components/EnterpriseLayout';
import { ToastProvider, useToast } from './components/ui/Toast';
import {
  addBatchTiles,
  addSingleTile,
  addZipTiles,
  deleteCatalogueTile,
  detectTiles,
  findSimilarByCrop,
  getCatalogueTile,
  getCatalogueStats,
  searchCatalogueByName,
  updateCatalogueTile,
} from './api';

function AppInner() {
  const addToast = useToast();

  const [activeTab, setActiveTab] = useState(() => {
    return window.location.pathname === '/visualizer' ? 'visualizer' : 'dashboard';
  });

  const handleTabChange = (tab) => {
    setActiveTab(tab);
    if (tab === 'visualizer') {
      window.history.pushState({}, '', '/visualizer');
    } else {
      window.history.pushState({}, '', '/');
    }
  };

  // --- Search State ---
  const [sourceImage, setSourceImage] = useState(null);
  const [detecting, setDetecting] = useState(false);
  const [crops, setCrops] = useState([]);
  const [selectedCrop, setSelectedCrop] = useState(null);
  const [matches, setMatches] = useState([]);
  const [searching, setSearching] = useState(false);
  const [stats, setStats] = useState(null);
  const [error, setError] = useState('');

  // --- Upload State ---
  const [addFile, setAddFile] = useState(null);
  const [addMode, setAddMode] = useState('single');
  const [batchFiles, setBatchFiles] = useState([]);
  const [batchCsv, setBatchCsv] = useState(null);
  const [zipFile, setZipFile] = useState(null);
  const [addForm, setAddForm] = useState({
    img_name: '', img_url: '', size: '', texture: '', color: '',
  });
  const [addingTile, setAddingTile] = useState(false);
  const [addResult, setAddResult] = useState('');

  // --- Manage State ---
  const [manageQuery, setManageQuery] = useState('');
  const [manageResults, setManageResults] = useState([]);
  const [managing, setManaging] = useState(false);
  const [editState, setEditState] = useState(null);
  const [editSaving, setEditSaving] = useState(false);

  const canSearch = useMemo(() => Boolean(selectedCrop), [selectedCrop]);

  // --- Actions ---
  async function loadStats() {
    try {
      const data = await getCatalogueStats();
      setStats(data.stats);
    } catch { /* keep UI usable */ }
  }

  async function onDetectSubmit(e) {
    e.preventDefault();
    if (!sourceImage) { setError('Pick an image first.'); return; }
    setError(''); setDetecting(true); setMatches([]); setSelectedCrop(null);
    try {
      const data = await detectTiles(sourceImage);
      setCrops(data.crops || []);
      if (!data.crops?.length) setError('No tiles detected in this image.');
    } catch (err) {
      setError(err.message || 'Detection failed.');
    } finally {
      setDetecting(false);
    }
  }

  async function onFindSimilar() {
    if (!selectedCrop) return;
    setSearching(true); setError('');
    try {
      const data = await findSimilarByCrop(selectedCrop.crop, 6);
      setMatches(data.results || []);
      addToast(`Found ${data.results?.length || 0} similar tiles`, 'success');
      await loadStats();
    } catch (err) {
      setError(err.message || 'Similarity search failed.');
    } finally {
      setSearching(false);
    }
  }

  async function onAddSingleTile(e) {
    e.preventDefault();
    if (!addFile) { setAddResult('Pick an image before uploading.'); return; }
    setAddingTile(true); setAddResult('');
    try {
      const res = await addSingleTile({ imageFile: addFile, ...addForm });
      setAddResult(`Added: ${res.tiles_added}, skipped: ${res.tiles_skipped_duplicates}, total: ${res.total_tiles_in_index}`);
      addToast('Tile uploaded successfully!', 'success');
      setAddFile(null);
      setAddForm({ img_name: '', img_url: '', size: '', texture: '', color: '' });
      await loadStats();
    } catch (err) {
      setAddResult(err.message || 'Upload failed.');
      addToast('Upload failed', 'error');
    } finally {
      setAddingTile(false);
    }
  }

  async function onAddBatchTiles(e) {
    e.preventDefault();
    if (!batchFiles.length || !batchCsv) { setAddResult('Select batch images and a CSV file.'); return; }
    setAddingTile(true); setAddResult('');
    try {
      const res = await addBatchTiles({ images: batchFiles, csvFile: batchCsv });
      setAddResult(`Added: ${res.tiles_added}, skipped: ${res.tiles_skipped_duplicates}, total: ${res.total_tiles_in_index}`);
      addToast('Batch upload complete!', 'success');
      setBatchFiles([]); setBatchCsv(null);
      await loadStats();
    } catch (err) {
      setAddResult(err.message || 'Batch upload failed.');
      addToast('Batch upload failed', 'error');
    } finally {
      setAddingTile(false);
    }
  }

  async function onAddZipTiles(e) {
    e.preventDefault();
    if (!zipFile) { setAddResult('Select a ZIP file first.'); return; }
    setAddingTile(true); setAddResult('');
    try {
      const res = await addZipTiles({ zipFile });
      setAddResult(`Added: ${res.tiles_added}, skipped: ${res.tiles_skipped_duplicates}, total: ${res.total_tiles_in_index}`);
      addToast('ZIP upload complete!', 'success');
      setZipFile(null);
      await loadStats();
    } catch (err) {
      setAddResult(err.message || 'ZIP upload failed.');
      addToast('ZIP upload failed', 'error');
    } finally {
      setAddingTile(false);
    }
  }

  async function onManageSearch(e) {
    if (e) e.preventDefault();
    if (!manageQuery.trim()) { setManageResults([]); return; }
    setManaging(true);
    try {
      const res = await searchCatalogueByName(manageQuery.trim(), 30);
      setManageResults(res.results || []);
    } catch (err) {
      setError(err.message || 'Search failed.');
    } finally {
      setManaging(false);
    }
  }

  async function openEdit(faissId) {
    try {
      const tile = await getCatalogueTile(faissId);
      setEditState({
        faiss_id: faissId,
        img_name: tile.img_name || '',
        img_url: tile.img_url || '',
        size: tile.size || '',
        texture: tile.texture || '',
        color: tile.color || '',
      });
    } catch (err) {
      setError(err.message || 'Failed to load tile details.');
    }
  }

  async function saveEdit(e) {
    e.preventDefault();
    if (!editState) return;
    setEditSaving(true);
    try {
      await updateCatalogueTile(editState.faiss_id, {
        img_url: editState.img_url,
        size: editState.size,
        texture: editState.texture,
        color: editState.color,
      });
      addToast('Tile updated successfully', 'success');
      await onManageSearch();
      await loadStats();
      setEditState(null);
    } catch (err) {
      setError(err.message || 'Failed to save changes.');
    } finally {
      setEditSaving(false);
    }
  }

  async function onDeleteTile(faissId, name) {
    const ok = window.confirm(`Delete tile '${name}'? This cannot be undone.`);
    if (!ok) return;
    try {
      await deleteCatalogueTile(faissId);
      addToast('Tile deleted', 'info');
      await onManageSearch();
      await loadStats();
    } catch (err) {
      setError(err.message || 'Failed to delete tile.');
    }
  }

  const pageTransition = {
    initial: { opacity: 0, y: 8 },
    animate: { opacity: 1, y: 0 },
    exit: { opacity: 0, y: -8 },
    transition: { duration: 0.2 },
  };

  return (
    <EnterpriseLayout activeTab={activeTab} onTabChange={handleTabChange}>
      <AnimatePresence mode="wait">
        {activeTab === 'dashboard' && (
          <motion.div key="dashboard" {...pageTransition}>
            <DashboardPage stats={stats} onLoadStats={loadStats} onTabChange={handleTabChange} />
          </motion.div>
        )}

        {activeTab === 'search' && (
          <motion.div key="search" {...pageTransition}>
            <SearchPage
              sourceImage={sourceImage} setSourceImage={setSourceImage}
              detecting={detecting} onDetectSubmit={onDetectSubmit}
              crops={crops} selectedCrop={selectedCrop} setSelectedCrop={setSelectedCrop}
              searching={searching} onFindSimilar={onFindSimilar} canSearch={canSearch}
              matches={matches} error={error}
            />
          </motion.div>
        )}

        {activeTab === 'add' && (
          <motion.div key="add" {...pageTransition}>
            <UploadTilePage
              addFile={addFile} setAddFile={setAddFile}
              addForm={addForm} setAddForm={setAddForm}
              addMode={addMode} setAddMode={setAddMode}
              batchFiles={batchFiles} setBatchFiles={setBatchFiles}
              batchCsv={batchCsv} setBatchCsv={setBatchCsv}
              zipFile={zipFile} setZipFile={setZipFile}
              addingTile={addingTile} addResult={addResult}
              onAddSingleTile={onAddSingleTile} onAddBatchTiles={onAddBatchTiles} onAddZipTiles={onAddZipTiles}
            />
          </motion.div>
        )}

        {activeTab === 'catalogue' && (
          <motion.div key="catalogue" {...pageTransition}>
            <CataloguePage
              stats={stats}
              manageQuery={manageQuery} setManageQuery={setManageQuery}
              manageResults={manageResults} onManageSearch={onManageSearch} managing={managing}
              onDeleteTile={onDeleteTile} openEdit={openEdit}
              editState={editState} setEditState={setEditState} saveEdit={saveEdit} editSaving={editSaving}
              onLoadStats={loadStats}
            />
          </motion.div>
        )}

        {activeTab === 'visualizer' && (
          <motion.div key="visualizer" {...pageTransition}>
            <Visualization />
          </motion.div>
        )}

        {activeTab === 'settings' && (
          <motion.div key="settings" {...pageTransition}>
            <SettingsPage />
          </motion.div>
        )}
      </AnimatePresence>

      {error && activeTab !== 'search' && (
        <div className="mt-4 p-3 rounded-xl bg-red-50 border border-red-200 text-red-600 text-sm font-medium">
          {error}
        </div>
      )}
    </EnterpriseLayout>
  );
}

export default function App() {
  return (
    <ToastProvider>
      <AppInner />
    </ToastProvider>
  );
}

import { useState } from 'react';
import { Search, Bell, User, ChevronRight, Home } from 'lucide-react';
import EnterpriseSidebar from './EnterpriseSidebar';

const TAB_LABELS = {
  dashboard: 'Dashboard',
  search: 'Search & Match',
  add: 'Upload Tile',
  catalogue: 'Catalogue',
  visualizer: 'Visualization',
  settings: 'Settings',
};

function TopNavbar({ activeTab }) {
  const [searchQuery, setSearchQuery] = useState('');

  return (
    <header className="sticky top-0 z-40 h-16 bg-white border-b border-surface-border flex items-center justify-between px-6 gap-4">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-sm text-slate-500 min-w-0">
        <Home size={14} className="flex-shrink-0 text-slate-400" />
        <ChevronRight size={12} className="flex-shrink-0 text-slate-300" />
        <span className="font-medium text-brand-navy truncate">
          {TAB_LABELS[activeTab] || 'Dashboard'}
        </span>
      </div>

      {/* Search */}
      <div className="flex-1 max-w-md mx-4">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
          <input
            type="text"
            placeholder="Search tiles, textures..."
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 rounded-xl border border-surface-border bg-surface-secondary text-sm focus:outline-none focus:border-brand-indigo focus:ring-2 focus:ring-brand-indigo/20 transition-all"
          />
        </div>
      </div>

      {/* Actions */}
      <div className="flex items-center gap-3 flex-shrink-0">
        <button className="relative w-9 h-9 rounded-xl bg-surface-secondary border border-surface-border flex items-center justify-center text-slate-500 hover:text-brand-navy hover:bg-surface-tertiary transition-colors">
          <Bell size={18} />
          <span className="absolute -top-0.5 -right-0.5 w-4 h-4 rounded-full bg-brand-orange text-white text-[9px] font-bold flex items-center justify-center">3</span>
        </button>
        <button className="w-9 h-9 rounded-xl bg-gradient-to-br from-brand-orange to-brand-orange-light flex items-center justify-center text-white">
          <User size={18} />
        </button>
      </div>
    </header>
  );
}

export default function EnterpriseLayout({ activeTab, onTabChange, sidebarCollapsed, children }) {
  return (
    <div className="flex min-h-screen bg-surface-secondary">
      <EnterpriseSidebar activeTab={activeTab} onTabChange={onTabChange} />
      {/* Main area — shifts with sidebar */}
      <div className="flex-1 ml-[260px] flex flex-col transition-all duration-300">
        <TopNavbar activeTab={activeTab} />
        <main className="flex-1 p-6 overflow-auto">
          {children}
        </main>
      </div>
    </div>
  );
}

import { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { CheckCircle, AlertCircle, Info, X } from 'lucide-react';

const ToastContext = createContext(null);

export function useToast() {
  return useContext(ToastContext);
}

function ToastItem({ toast, onRemove }) {
  const icons = {
    success: <CheckCircle size={18} className="text-emerald-500" />,
    error: <AlertCircle size={18} className="text-red-500" />,
    info: <Info size={18} className="text-brand-indigo" />,
  };
  const bgColors = {
    success: 'border-emerald-200 bg-emerald-50',
    error: 'border-red-200 bg-red-50',
    info: 'border-indigo-200 bg-indigo-50',
  };

  return (
    <div className={`flex items-start gap-3 px-4 py-3 rounded-xl border shadow-lg animate-slide-up ${bgColors[toast.type] || bgColors.info}`}>
      {icons[toast.type] || icons.info}
      <p className="text-sm font-medium text-slate-700 flex-1">{toast.message}</p>
      <button onClick={() => onRemove(toast.id)} className="text-slate-400 hover:text-slate-600 transition-colors">
        <X size={16} />
      </button>
    </div>
  );
}

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);

  const addToast = useCallback((message, type = 'info', duration = 4000) => {
    const id = Date.now() + Math.random();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), duration);
  }, []);

  const removeToast = useCallback((id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={addToast}>
      {children}
      {/* Toast container */}
      <div className="fixed bottom-6 right-6 z-[9999] flex flex-col gap-2 w-80">
        {toasts.map(t => (
          <ToastItem key={t.id} toast={t} onRemove={removeToast} />
        ))}
      </div>
    </ToastContext.Provider>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Database, Layers, Ruler, Palette, Search, LayoutGrid, List, ChevronLeft, ChevronRight, Pencil, Trash2 } from 'lucide-react';
import ImageWithFallback from '../components/ui/ImageWithFallback';
import TileCard from '../components/ui/TileCard';
import { SkeletonCard, SkeletonChart } from '../components/ui/SkeletonLoader';
import CatalogueStackedChart from '../components/charts/CatalogueStackedChart';
import TextureDonutChart from '../components/charts/TextureDonutChart';
import TimelineChart from '../components/charts/TimelineChart';
import { getTextureColor } from '../theme';
import { MAIN_API } from '../config/api';

const getImageUrl = (filename) => {
  if (!filename) return '';
  if (filename.startsWith('http')) return filename;
  const name = filename.split('/').pop();
  return `${MAIN_API}/static/tiles_images/${name}`;
};

const container = { hidden: { opacity: 0 }, show: { opacity: 1, transition: { staggerChildren: 0.06 } } };
const item = { hidden: { opacity: 0, y: 12 }, show: { opacity: 1, y: 0 } };

const ITEMS_PER_PAGE = 12;

export default function CataloguePage({
  stats,
  manageQuery, setManageQuery,
  manageResults, onManageSearch, managing,
  onDeleteTile, openEdit,
  editState, setEditState, saveEdit, editSaving,
  onLoadStats,
}) {
  const [viewMode, setViewMode] = useState('grid');
  const [page, setPage] = useState(1);
  const [textureFilter, setTextureFilter] = useState('');
  const [sizeFilter, setSizeFilter] = useState('');
  const [sortBy, setSortBy] = useState('name');

  useEffect(() => { onLoadStats(); }, []);

  const totalTiles = stats?.total || 0;
  const textureCount = Object.keys(stats?.textures || {}).length;
  const sizeCount = Object.keys(stats?.sizes || {}).length;
  const colorCount = Object.keys(stats?.colors || {}).length;

  // Filter and paginate results
  let filtered = [...manageResults];
  if (textureFilter) filtered = filtered.filter(t => t.texture === textureFilter);
  if (sizeFilter) filtered = filtered.filter(t => t.size === sizeFilter);
  if (sortBy === 'name') filtered.sort((a, b) => (a.img_name || '').localeCompare(b.img_name || ''));
  else if (sortBy === 'texture') filtered.sort((a, b) => (a.texture || '').localeCompare(b.texture || ''));

  const totalPages = Math.ceil(filtered.length / ITEMS_PER_PAGE) || 1;
  const paginated = filtered.slice((page - 1) * ITEMS_PER_PAGE, page * ITEMS_PER_PAGE);

  return (
    <motion.div variants={container} initial="hidden" animate="show" className="space-y-6">
      <motion.div variants={item}>
        <h1 className="text-2xl font-bold text-brand-navy">Catalogue</h1>
        <p className="text-sm text-slate-500 mt-1">Browse, filter, and manage your tile collection</p>
      </motion.div>

      {/* Summary pills */}
      <motion.div variants={item} className="flex flex-wrap gap-3">
        {[
          { label: 'Total Tiles', value: totalTiles, icon: Database },
          { label: 'Textures', value: textureCount, icon: Layers },
          { label: 'Sizes', value: sizeCount, icon: Ruler },
          { label: 'Colors', value: colorCount, icon: Palette },
        ].map(s => (
          <div key={s.label} className="flex items-center gap-2 px-4 py-2 rounded-full bg-white border border-surface-border text-sm">
            <s.icon size={14} className="text-brand-orange" />
            <span className="font-bold text-brand-navy">{s.value}</span>
            <span className="text-slate-500">{s.label}</span>
          </div>
        ))}
      </motion.div>

      {/* Filter bar */}
      <motion.div variants={item} className="flex flex-wrap items-center gap-3 p-4 rounded-xl bg-white border border-surface-border">
        <form onSubmit={onManageSearch} className="flex-1 min-w-[200px] flex gap-2">
          <div className="relative flex-1">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              placeholder="Search by tile name..."
              value={manageQuery}
              onChange={e => setManageQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-xl border border-surface-border text-sm focus:outline-none focus:border-brand-indigo focus:ring-2 focus:ring-brand-indigo/20"
            />
          </div>
          <button type="submit" className="px-4 py-2 rounded-xl bg-gradient-to-r from-brand-indigo to-brand-indigo-light text-white font-semibold text-sm hover:shadow-glow-indigo transition-all">
            {managing ? 'Searching...' : 'Search'}
          </button>
        </form>

        <select value={textureFilter} onChange={e => { setTextureFilter(e.target.value); setPage(1); }} className="px-3 py-2 rounded-xl border border-surface-border text-sm bg-white">
          <option value="">All Textures</option>
          {Object.keys(stats?.textures || {}).map(t => <option key={t} value={t}>{t}</option>)}
        </select>

        <select value={sizeFilter} onChange={e => { setSizeFilter(e.target.value); setPage(1); }} className="px-3 py-2 rounded-xl border border-surface-border text-sm bg-white">
          <option value="">All Sizes</option>
          {Object.keys(stats?.sizes || {}).map(s => <option key={s} value={s}>{s}</option>)}
        </select>

        <select value={sortBy} onChange={e => setSortBy(e.target.value)} className="px-3 py-2 rounded-xl border border-surface-border text-sm bg-white">
          <option value="name">Sort by Name</option>
          <option value="texture">Sort by Texture</option>
        </select>

        <div className="flex rounded-xl border border-surface-border overflow-hidden">
          <button onClick={() => setViewMode('grid')} className={`p-2 ${viewMode === 'grid' ? 'bg-brand-indigo text-white' : 'bg-white text-slate-500 hover:bg-surface-secondary'}`}>
            <LayoutGrid size={16} />
          </button>
          <button onClick={() => setViewMode('table')} className={`p-2 ${viewMode === 'table' ? 'bg-brand-indigo text-white' : 'bg-white text-slate-500 hover:bg-surface-secondary'}`}>
            <List size={16} />
          </button>
        </div>
      </motion.div>

      {/* Charts */}
      {stats && (
        <motion.div variants={item} className="grid grid-cols-1 lg:grid-cols-3 gap-4">
          <CatalogueStackedChart textures={stats.textures} sizes={stats.sizes} />
          <TextureDonutChart data={stats.colors} />
          <TimelineChart />
        </motion.div>
      )}

      {/* Tile Grid / Table */}
      <motion.div variants={item}>
        {filtered.length === 0 && manageResults.length === 0 ? (
          <div className="rounded-xl border border-surface-border bg-white p-12 text-center">
            <Search size={48} strokeWidth={1} className="mx-auto mb-3 text-slate-300" />
            <p className="text-slate-500 font-medium">Search to browse catalogue tiles</p>
            <p className="text-xs text-slate-400 mt-1">Type a tile name and click Search</p>
          </div>
        ) : viewMode === 'grid' ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {paginated.map(t => (
              <div key={t.faiss_id} className="relative group">
                <TileCard tile={t} />
                {/* Actions overlay */}
                <div className="absolute top-2 left-2 flex gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => openEdit(t.faiss_id)} className="w-8 h-8 rounded-lg bg-white/90 backdrop-blur flex items-center justify-center text-brand-indigo hover:bg-brand-indigo hover:text-white transition-all shadow">
                    <Pencil size={14} />
                  </button>
                  <button onClick={() => onDeleteTile(t.faiss_id, t.img_name)} className="w-8 h-8 rounded-lg bg-white/90 backdrop-blur flex items-center justify-center text-red-500 hover:bg-red-500 hover:text-white transition-all shadow">
                    <Trash2 size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="rounded-xl border border-surface-border bg-white overflow-hidden">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-surface-border bg-surface-secondary text-left">
                  <th className="px-4 py-3 font-semibold text-slate-600">Image</th>
                  <th className="px-4 py-3 font-semibold text-slate-600">Name</th>
                  <th className="px-4 py-3 font-semibold text-slate-600">Texture</th>
                  <th className="px-4 py-3 font-semibold text-slate-600">Size</th>
                  <th className="px-4 py-3 font-semibold text-slate-600">Color</th>
                  <th className="px-4 py-3 font-semibold text-slate-600">Actions</th>
                </tr>
              </thead>
              <tbody>
                {paginated.map(t => {
                  const texCls = getTextureColor(t.texture);
                  return (
                    <tr key={t.faiss_id} className="border-b border-surface-border hover:bg-surface-secondary transition-colors">
                      <td className="px-4 py-2.5"><ImageWithFallback src={getImageUrl(t.img_url)} alt={t.img_name} className="w-10 h-10 rounded-lg object-cover" /></td>
                      <td className="px-4 py-2.5 font-semibold text-brand-navy">{t.img_name}</td>
                      <td className="px-4 py-2.5"><span className={`text-xs px-2 py-0.5 rounded-full font-semibold ${texCls}`}>{t.texture || '-'}</span></td>
                      <td className="px-4 py-2.5 text-slate-600">{t.size || '-'}</td>
                      <td className="px-4 py-2.5 text-slate-600">{t.color || '-'}</td>
                      <td className="px-4 py-2.5">
                        <div className="flex gap-1.5">
                          <button onClick={() => openEdit(t.faiss_id)} className="p-1.5 rounded-lg text-brand-indigo hover:bg-brand-indigo/10 transition-colors"><Pencil size={14} /></button>
                          <button onClick={() => onDeleteTile(t.faiss_id, t.img_name)} className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 transition-colors"><Trash2 size={14} /></button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </motion.div>

      {/* Pagination */}
      {filtered.length > ITEMS_PER_PAGE && (
        <div className="flex items-center justify-center gap-2">
          <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1} className="p-2 rounded-lg border border-surface-border disabled:opacity-30 hover:bg-surface-secondary transition-colors">
            <ChevronLeft size={18} />
          </button>
          {Array.from({ length: Math.min(5, totalPages) }, (_, i) => i + 1).map(n => (
            <button key={n} onClick={() => setPage(n)} className={`w-9 h-9 rounded-lg text-sm font-semibold transition-all ${page === n ? 'bg-brand-indigo text-white' : 'border border-surface-border hover:bg-surface-secondary'}`}>
              {n}
            </button>
          ))}
          {totalPages > 5 && <span className="text-slate-400">…</span>}
          <button onClick={() => setPage(p => Math.min(totalPages, p + 1))} disabled={page === totalPages} className="p-2 rounded-lg border border-surface-border disabled:opacity-30 hover:bg-surface-secondary transition-colors">
            <ChevronRight size={18} />
          </button>
        </div>
      )}

      {/* Edit modal */}
      {editState && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={() => setEditState(null)}>
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="bg-white rounded-2xl p-6 w-full max-w-md shadow-xl"
            onClick={e => e.stopPropagation()}
          >
            <h3 className="text-lg font-bold text-brand-navy mb-4">Edit: {editState.img_name}</h3>
            <form onSubmit={saveEdit} className="space-y-3">
              {['img_url', 'size', 'texture', 'color'].map(field => (
                <input
                  key={field}
                  placeholder={field.replace('_', ' ').replace(/\b\w/g, c => c.toUpperCase())}
                  value={editState[field]}
                  onChange={e => setEditState(s => ({ ...s, [field]: e.target.value }))}
                  className="w-full px-4 py-2.5 rounded-xl border border-surface-border text-sm focus:outline-none focus:border-brand-indigo focus:ring-2 focus:ring-brand-indigo/20"
                />
              ))}
              <div className="flex gap-3 pt-2">
                <button type="submit" disabled={editSaving} className="flex-1 py-2.5 rounded-xl font-semibold text-white bg-gradient-to-r from-brand-orange to-brand-orange-light disabled:opacity-50 hover:shadow-glow-orange transition-all">
                  {editSaving ? 'Saving...' : 'Save Changes'}
                </button>
                <button type="button" onClick={() => setEditState(null)} className="px-4 py-2.5 rounded-xl font-semibold border-2 border-brand-navy text-brand-navy hover:bg-brand-navy hover:text-white transition-all">
                  Cancel
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </motion.div>
  );
}

import { useEffect } from 'react';
