                  <span className="mt-2 text-xs px-3 py-1 bg-brand-orange/10 text-brand-orange rounded-full font-medium">
                    {(sourceImage.size / 1024).toFixed(1)} KB
                  </span>
                )}
              </label>

              <button
                type="submit"
                disabled={detecting || !sourceImage}
                className="w-full mt-4 py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-brand-orange to-brand-orange-light disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-glow-orange transition-all duration-300 hover:-translate-y-0.5 flex items-center justify-center gap-2"
              >
                {detecting ? (
                  <><span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Detecting...</>
                ) : (
                  <><Sparkles size={18} /> Detect Tiles</>
                )}
              </button>
            </form>

            {error && (
              <div className="p-3 rounded-xl bg-red-50 border border-red-200 text-red-600 text-sm font-medium">
                {error}
              </div>
            )}

            {/* Crop Selection */}
            {crops.length > 0 && (
              <div>
                <h3 className="text-sm font-semibold text-brand-navy mb-3">Pick a Crop</h3>
                <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
                  {crops.map((crop) => {
                    const active = selectedCrop?.crop === crop.crop;
                    return (
                      <button
                        key={crop.crop}
                        type="button"
                        onClick={() => setSelectedCrop(crop)}
                        className={`relative aspect-square rounded-xl overflow-hidden border-2 transition-all duration-200 ${
                          active
                            ? 'border-brand-orange shadow-glow-orange ring-2 ring-brand-orange/30'
                            : 'border-surface-border hover:border-brand-orange/50'
                        }`}
                      >
                        <img src={getImageUrl(crop.url)} alt={crop.crop} className="w-full h-full object-cover" />
                        {active && (
                          <div className="absolute inset-0 bg-brand-orange/10 flex items-center justify-center">
                            <span className="text-xs font-bold bg-brand-orange text-white px-2 py-0.5 rounded-full">Selected</span>
                          </div>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            <button
              type="button"
              disabled={!canSearch || searching}
              onClick={onFindSimilar}
              className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-brand-indigo to-brand-indigo-light disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-glow-indigo transition-all duration-300 hover:-translate-y-0.5 flex items-center justify-center gap-2"
            >
              {searching ? (
                <><span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Searching...</>
              ) : (
                <><Search size={18} /> Find Similar Tiles</>
              )}
            </button>
          </div>
        </motion.div>

        {/* RIGHT — Results */}
        <motion.div variants={item}>
          <div className="rounded-xl border border-surface-border bg-white p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold text-brand-navy">Similarity Results</h2>
              {matches.length > 0 && (
                <span className="text-xs px-2.5 py-1 rounded-full bg-emerald-100 text-emerald-700 font-semibold">
                  {matches.length} found
                </span>
              )}
            </div>

            {matches.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-16 text-slate-400">
                <Search size={48} strokeWidth={1} className="mb-3 opacity-40" />
                <p className="text-sm font-medium">No results yet</p>
                <p className="text-xs mt-1">Select a crop and search to see matches</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-4">
                {matches.map((m, idx) => {
                  const scorePct = Math.round((m.score || 0) * 1000) / 10;
                  const scoreCls = getScoreColor(m.score);
                  const texCls = getTextureColor(m.texture);
                  return (
                    <motion.div
                      key={`${m.name}-${idx}`}
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      transition={{ delay: idx * 0.05 }}
                      className="group rounded-xl border border-surface-border overflow-hidden hover:shadow-card-hover hover:-translate-y-1 transition-all duration-300"
                    >
                      <div className="relative aspect-square bg-slate-100">
                        <ImageWithFallback
                          src={getImageUrl(m.image)}
                          alt={m.name}
                          className="w-full h-full object-cover"
                        />
                        <span className={`absolute top-2 right-2 text-xs px-2 py-0.5 rounded-full font-bold border ${scoreCls}`}>
                          {scorePct}%
                        </span>
                      </div>
                      <div className="p-3 space-y-1.5">
                        <h3 className="text-sm font-semibold text-brand-navy truncate">{m.name}</h3>
                        {m.texture && (
                          <span className={`inline-block text-[10px] px-2 py-0.5 rounded-full font-semibold ${texCls}`}>{m.texture}</span>
                        )}
                        <div className="text-xs text-slate-500 space-y-0.5">
                          {m.size && <p>📐 Size: {m.size}</p>}
                          {m.color && <p>🎨 Color: {m.color}</p>}
                        </div>
                      </div>
                    </motion.div>
                  );
                })}
              </div>
            )}
          </div>
        </motion.div>
      </div>
    </motion.div>
  );
}

